  const escaped = escapeRegExp(packageName);
  return sourceText
    .replace(
      new RegExp(`from\\s+['"]${escaped}['"]`, 'g'),
      `from '${shimSpecifier}'`
    )
    .replace(
      new RegExp(`import\\s+['"]${escaped}['"]`, 'g'),
      `import '${shimSpecifier}'`
    )
    .replace(
      new RegExp(`require\\(['"]${escaped}['"]\\)`, 'g'),
      `require('${shimSpecifier}')`
    );
