async function importCapturedSource(filePath, frameworkId) {
  const absolutePath = path.resolve(filePath);
  const sourceDirectory = path.dirname(absolutePath);
  const sourceText = fs.readFileSync(absolutePath, 'utf8');
  const moduleFlavor = detectModuleFlavor(sourceText, absolutePath);
  const tempExtension = compatibilityTempExtension(absolutePath, moduleFlavor);
  const nonce = `${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
  const tempSourcePath = path.join(
    sourceDirectory,
    `.${path.basename(
      absolutePath,
      path.extname(absolutePath)
    )}.xgnosis.${nonce}${tempExtension}`
  );
  const shimExtension = moduleFlavor === 'cjs' ? '.cjs' : '.mjs';
  const shims = frameworkShims(frameworkId, moduleFlavor);
  let rewrittenSource = sourceText;
  const shimFilePaths = [];

  for (const [index, shim] of shims.entries()) {
    const packageToken = shim.packageName
      .replace(/[^a-zA-Z0-9]+/g, '_')
      .replace(/^_+|_+$/g, '');
    const shimFilePath = path.join(
      sourceDirectory,
      `.${path.basename(
        absolutePath,
        path.extname(absolutePath)
      )}.xgnosis.${nonce}.${index}.${packageToken}.shim${shimExtension}`
    );
    const shimSpecifier = relativeShimSpecifier(
      sourceDirectory,
      shimFilePath,
      moduleFlavor
    );
    rewrittenSource = rewritePackageImport(
      rewrittenSource,
      shim.packageName,
      shimSpecifier
    );
    fs.writeFileSync(shimFilePath, shim.source, 'utf8');
    shimFilePaths.push(shimFilePath);
  }

  fs.writeFileSync(tempSourcePath, rewrittenSource, 'utf8');

  clearRegistry();

  try {
    await import(`${pathToFileURL(tempSourcePath).href}?t=${Date.now()}`);
    const apps = registry();
    const selected =
      apps.find((candidate) => candidate?.__xgnosis?.listened) ??
      apps.find((candidate) => candidate?.__xgnosis?.kind === 'app') ??
      apps.find(
        (candidate) => candidate?.__xgnosis?.framework === frameworkId
      ) ??
      null;

    if (!selected) {
      throw new Error(
        `No ${frameworkId} compatibility app could be captured from ${filePath}.`
      );
    }

    return selected;
  } finally {
    clearRegistry();
    fs.rmSync(tempSourcePath, { force: true });
    for (const shimFilePath of shimFilePaths) {
      fs.rmSync(shimFilePath, { force: true });
    }
  }
}

/**
 * Handles the gnosis execute Node Framework Compatibility workflow.
 */
export async function executeNodeFrameworkCompatibility(request) {
  const compatibility = request.compatibility;
  if (!compatibility || compatibility.family !== 'node-router') {
    throw new Error('Missing node-router compatibility request.');
  }

  if (
    compatibility.framework !== 'express' &&
    compatibility.framework !== 'hono' &&
    compatibility.framework !== 'koa' &&
    compatibility.framework !== 'fastify'
  ) {
    return {
      matched: false,
    };
  }

  const app = await importCapturedSource(
    request.filePath,
    compatibility.framework
  );
  const invocation = {
    method: String(compatibility.request.method).toUpperCase(),
    path: normalizePathname(compatibility.request.path),
    query: compatibility.request.query ?? '',
    headers: normalizeResponseHeaders(compatibility.request.headers ?? {}),
    body: compatibility.request.body ?? null,
  };

  if (compatibility.framework === 'hono') {
    return dispatchHonoApp(app, invocation);
  }

  if (compatibility.framework === 'koa') {
    return dispatchKoaApp(app, invocation);
  }

  if (compatibility.framework === 'fastify') {
    return dispatchFastifyApp(app, invocation);
  }

  return dispatchExpressApp(app, invocation);
}
